148	func deleteNodePorts(service *corev1api.Service) error {
149		if service.Spec.Type == corev1api.ServiceTypeExternalName {
150			return nil
151		}
152	
153		// find any NodePorts whose values were explicitly specified according
154		// to the last-applied-config annotation. We'll retain these values, and
155		// clear out any other (presumably auto-assigned) NodePort values.
156		lastAppliedConfig, ok := service.Annotations[annotationLastAppliedConfig]
157		if ok {
158			explicitNodePorts := sets.NewString()
159			unnamedPortInts := sets.NewInt()
160			appliedServiceUnstructured := new(map[string]any)
161			if err := json.Unmarshal([]byte(lastAppliedConfig), appliedServiceUnstructured); err != nil {
162				return errors.WithStack(err)
163			}
164	
165			ports, bool, err := unstructured.NestedSlice(*appliedServiceUnstructured, "spec", "ports")
166	
167			if err != nil {
168				return errors.WithStack(err)
169			}
170	
171			if bool {
172				for _, port := range ports {
173					p, ok := port.(map[string]any)
174					if !ok {
175						continue
176					}
177					nodePort, nodePortBool, err := unstructured.NestedFieldNoCopy(p, "nodePort")
178					if err != nil {
179						return errors.WithStack(err)
180					}
181					if nodePortBool {
182						nodePortInt := 0
183						switch nodePort := nodePort.(type) {
184						case int32:
185							nodePortInt = int(nodePort)
186						case float64:
187							nodePortInt = int(nodePort)
188						case string:
189							nodePortInt, err = strconv.Atoi(nodePort)
190							if err != nil {
191								return errors.WithStack(err)
192							}
193						}
194						if nodePortInt > 0 {
195							portName, ok := p["name"]
196							if !ok {
197								// unnamed port
198								unnamedPortInts.Insert(nodePortInt)
199							} else {
200								explicitNodePorts.Insert(portName.(string))
201							}
202						}
203					}
204				}
205			}
206	
207			for i, port := range service.Spec.Ports {
208				if port.Name != "" {
209					if !explicitNodePorts.Has(port.Name) {
210						service.Spec.Ports[i].NodePort = 0
211					}
212				} else {
213					if !unnamedPortInts.Has(int(port.NodePort)) {
214						service.Spec.Ports[i].NodePort = 0
215					}
216				}
217			}
218	
219			return nil
220		}
221	
222		explicitNodePorts := sets.NewString()
223		for _, entry := range service.GetManagedFields() {
224			if entry.FieldsV1 == nil {
225				continue
226			}
227			fields := new(map[string]any)
228			if err := json.Unmarshal(entry.FieldsV1.Raw, fields); err != nil {
229				return errors.WithStack(err)
230			}
231	
232			ports, exist, err := unstructured.NestedMap(*fields, "f:spec", "f:ports")
233			if err != nil {
234				return errors.WithStack(err)
235			}
236			if !exist {
237				continue
238			}
239			for key, port := range ports {
240				p, ok := port.(map[string]any)
241				if !ok {
242					continue
243				}
244				if _, exist := p["f:nodePort"]; exist {
245					explicitNodePorts.Insert(key)
246				}
247			}
248		}
249		for i, port := range service.Spec.Ports {
250			k := portKey(port)
251			if !explicitNodePorts.Has(k) {
252				service.Spec.Ports[i].NodePort = 0
253			}
254		}
255		return nil
256	}
